16	namespace rime {
17	
18	class ModuleManager {
19	 public:
20	  // module is supposed to be a pointer to static variable
21	  void Register(const string& name, RimeModule* module);
22	  RimeModule* Find(const string& name);
23	
24	  void LoadModule(RimeModule* module);
25	  void UnloadModules();
26	
27	  static ModuleManager& instance();
28	
29	 private:
30	  ModuleManager() {}
31	
32	  // module registry
33	  using ModuleMap = map<string, RimeModule*>;
