8	#include <rime/module.h>
9	#include <rime_api.h>
10	
11	namespace rime {
12	
13	void ModuleManager::Register(const string& name, RimeModule* module) {
14	  map_[name] = module;
15	}
16	
17	RimeModule* ModuleManager::Find(const string& name) {
18	  ModuleMap::const_iterator it = map_.find(name);
19	  if (it != map_.end()) {
20	    return it->second;
21	  }
22	  return NULL;
23	}
24	
25	void ModuleManager::LoadModule(RimeModule* module) {
26	  if (!module || loaded_.find(module) != loaded_.end()) {
27	    return;
28	  }
29	  DLOG(INFO) << "loading module: " << module->module_name;
30	  loaded_.insert(module);
31	  if (module->initialize != NULL) {
32	    module->initialize();
33	  } else {
34	    LOG(WARNING) << "missing initialize() function in module: "
35	                 << module->module_name;
36	  }
37	}
38	
39	void ModuleManager::UnloadModules() {
40	  for (auto module : loaded_) {
41	    if (module->finalize != NULL) {
42	      module->finalize();
43	    }
44	  }
45	  loaded_.clear();
46	}
47	
48	ModuleManager& ModuleManager::instance() {
49	  static the<ModuleManager> s_instance;
50	  if (!s_instance) {
51	    s_instance.reset(new ModuleManager);
52	  }
53	  return *s_instance;
54	}
55	
56	}  // namespace rime
