7	#include <rime/common.h>
8	#include <rime/component.h>
9	#include <rime/registry.h>
10	
11	namespace rime {
12	
13	void Registry::Register(const string& name, ComponentBase* component) {
14	  LOG(INFO) << "registering component: " << name;
15	  if (ComponentBase* existing = Find(name)) {
16	    LOG(WARNING) << "replacing previously registered component: " << name;
17	    delete existing;
18	  }
19	  map_[name] = component;
20	}
21	
22	void Registry::Unregister(const string& name) {
23	  LOG(INFO) << "unregistering component: " << name;
24	  ComponentMap::iterator it = map_.find(name);
25	  if (it == map_.end())
26	    return;
27	  delete it->second;
28	  map_.erase(it);
29	}
30	
31	void Registry::Clear() {
32	  ComponentMap::iterator it = map_.begin();
33	  while (it != map_.end()) {
34	    delete it->second;
35	    map_.erase(it++);
36	  }
37	}
38	
39	ComponentBase* Registry::Find(const string& name) {
40	  ComponentMap::const_iterator it = map_.find(name);
41	  if (it != map_.end()) {
42	    return it->second;
43	  }
44	  return NULL;
45	}
46	
47	Registry& Registry::instance() {
48	  static the<Registry> s_instance;
49	  if (!s_instance) {
50	    s_instance.reset(new Registry);
51	  }
52	  return *s_instance;
53	}
54	
55	}  // namespace rime
