48	RIME_DLL void LoadModules(const char* module_names[]) {
49	  ModuleManager& mm(ModuleManager::instance());
50	  for (const char** m = module_names; *m; ++m) {
51	    if (RimeModule* module = mm.Find(*m)) {
52	      mm.LoadModule(module);
53	    }
54	  }
55	}
