57	RIME_DLL void SetupDeployer(RimeTraits* traits) {
58	  if (!traits)
59	    return;
60	  Deployer& deployer(Service::instance().deployer());
61	  if (RIME_PROVIDED(traits, shared_data_dir))
62	    deployer.shared_data_dir = path(traits->shared_data_dir);
63	  if (RIME_PROVIDED(traits, user_data_dir))
64	    deployer.user_data_dir = path(traits->user_data_dir);
65	  if (RIME_PROVIDED(traits, distribution_name))
66	    deployer.distribution_name = traits->distribution_name;
67	  if (RIME_PROVIDED(traits, distribution_code_name))
68	    deployer.distribution_code_name = traits->distribution_code_name;
69	  if (RIME_PROVIDED(traits, distribution_version))
70	    deployer.distribution_version = traits->distribution_version;
71	  if (RIME_PROVIDED(traits, app_name))
72	    deployer.app_name = traits->app_name;
73	  if (RIME_PROVIDED(traits, prebuilt_data_dir))
74	    deployer.prebuilt_data_dir = path(traits->prebuilt_data_dir);
75	  else
76	    deployer.prebuilt_data_dir = deployer.shared_data_dir / "build";
77	  if (RIME_PROVIDED(traits, staging_dir))
78	    deployer.staging_dir = path(traits->staging_dir);
79	  else
80	    deployer.staging_dir = deployer.user_data_dir / "build";
81	}
