83	RIME_DLL void SetupLogging(const char* app_name,
84	                           int min_log_level,
85	                           const char* log_dir) {
86	#ifdef RIME_ENABLE_LOGGING
87	  FLAGS_minloglevel = min_log_level;
88	#ifdef RIME_ALSO_LOG_TO_STDERR
89	  FLAGS_alsologtostderr = true;
90	#endif  // RIME_ALSO_LOG_TO_STDERR
91	  if (log_dir) {
92	    if (log_dir[0] == '\0') {
93	      google::LogToStderr();
94	    } else {
95	      FLAGS_log_dir = log_dir;
96	    }
97	  }
98	  google::SetLogFilenameExtension(".log");
99	  google::SetLogSymlink(google::GLOG_INFO, app_name);
100	  google::SetLogSymlink(google::GLOG_WARNING, app_name);
101	  google::SetLogSymlink(google::GLOG_ERROR, app_name);
102	  // Do not allow other users to read/write log files created by current
103	  // process.
104	  FLAGS_logfile_mode = 0600;
105	  if (google::IsGoogleLoggingInitialized()) {
106	    LOG(WARNING) << "Glog is already initialized.";
107	  } else {
108	    google::InitGoogleLogging(app_name);
109	  }
110	#endif  // RIME_ENABLE_LOGGING
111	}
112	
113	RIME_DLL void SetupLogging(const char* app_name) {
114	  SetupLogging(app_name, 0, NULL);
115	}
