19	static void rime_core_initialize() {
20	  LOG(INFO) << "registering core components.";
21	  Registry& r = Registry::instance();
22	
23	  auto config_builder =
24	      new ConfigComponent<ConfigBuilder>([&](ConfigBuilder* builder) {
25	        builder->InstallPlugin(new AutoPatchConfigPlugin);
26	        builder->InstallPlugin(new DefaultConfigPlugin);
27	        builder->InstallPlugin(new LegacyPresetConfigPlugin);
28	        builder->InstallPlugin(new LegacyDictionaryConfigPlugin);
29	        builder->InstallPlugin(new BuildInfoPlugin);
30	        builder->InstallPlugin(new SaveOutputPlugin);
31	      });
32	  r.Register("config_builder", config_builder);
33	
34	  auto config_loader =
35	      new ConfigComponent<ConfigLoader, DeployedConfigResourceProvider>;
36	  r.Register("config", config_loader);
37	  r.Register("schema", new SchemaComponent(config_loader));
38	
39	  auto user_config =
40	      new ConfigComponent<ConfigLoader, UserConfigResourceProvider>(
41	          [](ConfigLoader* loader) { loader->set_auto_save(true); });
42	  r.Register("user_config", user_config);
43	}
44	
45	static void rime_core_finalize() {
46	  // registered components have been automatically destroyed prior to this call
47	}
48	
