35	void PluginManager::LoadPlugins(path plugins_dir) {
36	  ModuleManager& mm = ModuleManager::instance();
37	  if (!fs::is_directory(plugins_dir)) {
38	    return;
39	  }
40	  LOG(INFO) << "loading plugins from " << plugins_dir;
41	  for (fs::directory_iterator iter(plugins_dir), end; iter != end; ++iter) {
42	    path plugin_file = iter->path();
43	    if (plugin_file.extension() == boost::dll::shared_library::suffix()) {
44	      fs::file_status plugin_file_status = fs::status(plugin_file);
45	      if (fs::is_regular_file(plugin_file_status)) {
46	        DLOG(INFO) << "found plugin: " << plugin_file;
47	        string plugin_name = plugin_name_of(plugin_file);
48	        if (plugin_libs_.find(plugin_name) == plugin_libs_.end()) {
49	          LOG(INFO) << "loading plugin '" << plugin_name << "' from "
50	                    << plugin_file;
51	          try {
52	            auto plugin_lib = boost::dll::shared_library(plugin_file);
53	            plugin_libs_[plugin_name] = plugin_lib;
54	          } catch (const std::exception& ex) {
55	            LOG(ERROR) << "error loading plugin " << plugin_name << ": "
56	                       << ex.what();
57	            continue;
58	          }
59	        }
60	        if (RimeModule* module = mm.Find(plugin_name)) {
61	          mm.LoadModule(module);
62	          LOG(INFO) << "loaded plugin: " << plugin_name;
63	        } else {
64	          LOG(WARNING) << "module '" << plugin_name
65	                       << "' is not provided by plugin library " << plugin_file;
66	        }
67	      }
68	    }
69	  }
70	}
71	
72	string PluginManager::plugin_name_of(path plugin_file) {
73	  string name = plugin_file.stem().string();
74	  // remove prefix "(lib)rime-"
75	  if (boost::starts_with(name, "librime-")) {
76	    boost::erase_first(name, "librime-");
77	  } else if (boost::starts_with(name, "rime-")) {
78	    boost::erase_first(name, "rime-");
79	  }
80	  // replace dash with underscore, for the plugin name is part of the module
81	  // initializer function name.
82	  std::replace(name.begin(), name.end(), '-', '_');
83	  return name;
84	}
85	
86	PluginManager& PluginManager::instance() {
87	  static the<PluginManager> s_instance;
88	  if (!s_instance) {
89	    s_instance.reset(new PluginManager);
90	  }
91	  return *s_instance;
92	}
