104	inline static rime::path symbol_location(const void* symbol) {
105	  Dl_info info;
106	  // Some of the libc headers miss `const` in `dladdr(const void*, Dl_info*)`
107	  const int res = dladdr(const_cast<void*>(symbol), &info);
108	  if (res) {
109	    return rime::path{info.dli_fname};
110	  } else {
111	    return rime::path{};
112	  }
113	}
114	
115	inline static rime::path current_module_path() {
116	  void rime_require_module_plugins();
117	  return symbol_location(
118	      reinterpret_cast<const void*>(&rime_require_module_plugins));
119	}
120	#endif
