97	static Bool rime_levers_get_available_schema_list(
98	    RimeSwitcherSettings* settings,
99	    RimeSchemaList* list) {
100	  auto ss = reinterpret_cast<SwitcherSettings*>(settings);
101	  list->size = 0;
102	  list->list = NULL;
103	  if (ss->available().empty()) {
104	    return False;
105	  }
106	  list->list = new RimeSchemaListItem[ss->available().size()];
107	  for (const auto& info : ss->available()) {
108	    auto& item(list->list[list->size]);
109	    item.schema_id = const_cast<char*>(info.schema_id.c_str());
110	    item.name = const_cast<char*>(info.name.c_str());
111	    item.reserved = const_cast<SchemaInfo*>(&info);
112	    ++list->size;
113	  }
114	  return True;
115	}
